// LESSON: Reference Page 1 - Lambdas och funktionella interface.
// You will learn: Pass behavior with lambdas, predicates, comparators, and functions.
class Prog2Reference437 {
  // EXEMPEL 1: Predicate<T> beskriver ett test som returnerar boolean.
  static boolean isLongName(String name) {
    java.util.function.Predicate<String> longName = text -> text.length() > 5;
    return longName.test(name);
  }
  // EXEMPEL 2: Function<T,R> gor om ett varde till ett annat.
  static int lengthOf(String text) {
    java.util.function.Function<String, Integer> length = value -> value.length();
    return length.apply(text);
  }
  // EXEMPEL 3: Ett eget funktionellt interface kan anvandas med lambda.
  interface Calculator {
    int apply(int a, int b);
  }
  static int addWithLambda(int left, int right) {
    Calculator add = (a, b) -> a + b;
    return add.apply(left, right);
  }
}
